function o(t){if(!t)return"";const n=String(t.getDate()).padStart(2,"0"),r=String(t.getMonth()+1).padStart(2,"0"),e=t.getFullYear();return`${n}/${r}/${e}`}function s(t){if(!t)return"";const n=t.getFullYear(),r=String(t.getMonth()+1).padStart(2,"0"),e=String(t.getDate()).padStart(2,"0");return`${n}-${r}-${e}`}function i(t){if(!t)return null;const[n,r,e]=String(t).split("-").map(Number),a=new Date(n,r-1,e);return a.setHours(0,0,0,0),a}function u(t){if(!t||typeof t!="string")return"";const n=t.trim().split(/[/\-.]/);if(n.length!==3)return"";const r=n[0].padStart(2,"0"),e=n[1].padStart(2,"0"),a=n[2];return r.length>2||e.length>2||a.length!==4?"":`${a}-${e}-${r}`}export{i as a,o as b,s as f,u as p};
